import{_ as a,o,c as e,ag as d,ah as r}from"./chunks/framework.D9bIGSBm.js";const f=JSON.parse('{"title":"文件与编辑器","description":"","frontmatter":{},"headers":[],"relativePath":"features/files-and-editor.md","filePath":"features/files-and-editor.md"}'),s={name:"features/files-and-editor.md"};function n(i,t,l,h,c,p){return o(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="文件与编辑器" tabindex="-1">文件与编辑器 <a class="header-anchor" href="#文件与编辑器" aria-label="Permalink to &quot;文件与编辑器&quot;">​</a></h1><p>右侧面板内置了一套完整的文件管理与编辑能力：浏览项目目录、打开文件查看或修改、对比前后差异、预览 Markdown……无需切换到外部编辑器，一切在应用内完成。</p><blockquote><p>相关基础：<a href="/docs/guide/interface-overview.html">界面导览</a></p></blockquote><hr><h2 id="文件树" tabindex="-1">文件树 <a class="header-anchor" href="#文件树" aria-label="Permalink to &quot;文件树&quot;">​</a></h2><p><strong>文件树</strong>是右侧面板的第一个标签页，展示当前工作区的完整目录结构，并实时监听磁盘变动——AI 新建或删除文件时，文件树会自动刷新，无需手动操作。</p><h3 id="打开文件树" tabindex="-1">打开文件树 <a class="header-anchor" href="#打开文件树" aria-label="Permalink to &quot;打开文件树&quot;">​</a></h3><p>点击标题栏的<strong>侧边面板</strong>按钮，打开右侧面板后选择<strong>文件树</strong>标签页即可。</p><p><img src="'+r+'" alt="截图：右侧面板文件树标签页，展示工作区目录结构，标签栏从左到右依次为文件树、编辑器、审查、浏览器"></p><h3 id="新建文件与文件夹" tabindex="-1">新建文件与文件夹 <a class="header-anchor" href="#新建文件与文件夹" aria-label="Permalink to &quot;新建文件与文件夹&quot;">​</a></h3><p>在文件树顶部工具栏，点击对应按钮可新建文件或文件夹：</p><ol><li>点击<strong>新建文件</strong>或<strong>新建文件夹</strong>按钮。</li><li>输入框出现，输入文件名（或文件夹名）后按回车确认，点击<strong>创建</strong>即完成。</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>文件名不能包含路径分隔符，也不能为 <code>.</code> 或 <code>..</code>。</p></div><h3 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h3><p>在文件树中右键单击文件或文件夹，弹出快捷菜单，包含以下操作：</p><table tabindex="0"><thead><tr><th>菜单项</th><th>快捷键</th><th>说明</th></tr></thead><tbody><tr><td><strong>复制</strong></td><td>Ctrl+C</td><td>复制选中文件到系统剪贴板</td></tr><tr><td><strong>剪切</strong></td><td>Ctrl+X</td><td>剪切选中文件到系统剪贴板</td></tr><tr><td><strong>粘贴</strong></td><td>Ctrl+V</td><td>粘贴剪贴板中的文件（剪贴板没有文件时该项置灰）</td></tr><tr><td><strong>重命名</strong></td><td>F2</td><td>将文件或文件夹改名</td></tr><tr><td><strong>删除</strong></td><td>Del</td><td>删除选中文件或文件夹</td></tr><tr><td><strong>在资源管理器中查看</strong></td><td>—</td><td>在系统资源管理器中定位并高亮该文件</td></tr><tr><td><strong>复制绝对路径</strong></td><td>—</td><td>将文件的完整绝对路径复制到剪贴板</td></tr><tr><td><strong>复制相对路径</strong></td><td>—</td><td>将相对工作区根目录的路径复制到剪贴板</td></tr><tr><td><strong>新建文件</strong></td><td>—</td><td>在当前目录下新建文件</td></tr><tr><td><strong>新建文件夹</strong></td><td>—</td><td>在当前目录下新建文件夹</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>表中带快捷键的操作不必打开菜单——在文件树中选中条目后直接按对应按键即可，支持多选后批量复制、剪切或删除。</p></div><hr><h2 id="编辑器" tabindex="-1">编辑器 <a class="header-anchor" href="#编辑器" aria-label="Permalink to &quot;编辑器&quot;">​</a></h2><p><strong>编辑器</strong>标签页集成了 Monaco（与 VS Code 同款的代码编辑内核），支持语法高亮、Diff 对比视图，以及 Markdown 预览。</p><h3 id="打开文件" tabindex="-1">打开文件 <a class="header-anchor" href="#打开文件" aria-label="Permalink to &quot;打开文件&quot;">​</a></h3><p><strong>方式一：双击文件树中的文件</strong>，文件在编辑器标签页中打开。</p><p><strong>方式二：Ctrl+P 文件搜索面板</strong>——在任意位置按 Ctrl+P，弹出搜索面板，输入文件名关键词后按回车即可打开目标文件。</p><p><strong>方式三：从输入框内打开文件</strong>——在对话输入框输入 <code>@</code> 选择文件，详见下文「在对话中 @ 引用文件」一节。</p><p><strong>方式四：拖拽文件</strong>（v0.3.2 起）——从系统资源管理器拖任意文件到文件面板、文件树或输入框，即可在编辑器中打开并编辑，支持<strong>工作区以外</strong>的文件。工作区以外的文件以面包屑形式（逐级目录路径）显示其完整的绝对路径，其标签页左侧色条与文件名会以警示色显示，提醒你它不属于当前工作区。</p><h3 id="保存文件" tabindex="-1">保存文件 <a class="header-anchor" href="#保存文件" aria-label="Permalink to &quot;保存文件&quot;">​</a></h3><p>编辑完成后按 <strong>Ctrl+S</strong> 保存当前文件。若关闭标签页时有未保存的更改，会弹出确认对话框，提示「要保存对 <em>[文件名]</em> 的修改吗？」——选<strong>不保存</strong>直接关闭，否则先保存再关闭。</p><p><img src="'+r+'" alt="截图：编辑器标签页，Monaco 编辑器展示一段 TypeScript 代码，语法高亮，标签栏左侧有文件名"></p><h3 id="diff-对比视图" tabindex="-1">Diff 对比视图 <a class="header-anchor" href="#diff-对比视图" aria-label="Permalink to &quot;Diff 对比视图&quot;">​</a></h3><p>AI 修改文件时，对话区的工具卡片会内联显示 Diff（新旧代码行级对比，红绿高亮）。如需在编辑器中进行完整 Diff 查看，请切换到<strong>审查</strong>标签页（详见 <a href="/docs/features/git.html#审查面板">Git 集成 → 审查面板</a>）。</p><h3 id="markdown-预览" tabindex="-1">Markdown 预览 <a class="header-anchor" href="#markdown-预览" aria-label="Permalink to &quot;Markdown 预览&quot;">​</a></h3><p>打开 <code>.md</code> 文件后，编辑器标签页右上角出现<strong>切换到预览</strong>按钮，点击即可渲染 Markdown 预览；点击<strong>切换到编辑</strong>返回源码视图。</p><hr><h2 id="在对话中-引用文件" tabindex="-1">在对话中 @ 引用文件 <a class="header-anchor" href="#在对话中-引用文件" aria-label="Permalink to &quot;在对话中 @ 引用文件&quot;">​</a></h2><p>在对话输入框输入 <code>@</code>，弹出文件选择面板，选中文件后，文件内容以上下文的形式附加到本条消息，供 AI 参考。适合让 AI 分析特定文件时使用。</p><p>详细的 <code>@</code> 引用用法见<a href="/docs/features/conversation.html">对话面板</a>。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>了解文件与编辑器后，接下来看看如何使用集成终端在工作区内运行命令——前往<a href="/docs/features/terminal.html">集成终端</a>继续学习。</p>',39)])])}const u=a(s,[["render",n]]);export{f as __pageData,u as default};
